void editorProcessKeypress(int fd) {
    static int quit_times = KILO_QUIT_TIMES;
    int c = editorReadKey(fd);
    switch(c) {
    case ENTER: editorInsertNewline(); break;
    case CTRL_C: break; /* ignored on purpose */
    case CTRL_Q:
        if (E.dirty && quit_times) {
            editorSetStatusMessage("WARNING!!! ... %d more times to quit.", quit_times);
            quit_times--; return;
        }
        exit(0); break;
    case CTRL_S: editorSave(); break;
    case CTRL_F: editorFind(fd); break;
    case BACKSPACE: case CTRL_H: case DEL_KEY: editorDelChar(); break;
    case PAGE_UP: case PAGE_DOWN: {
        if (c == PAGE_UP && E.cy != 0) E.cy = 0;
        else if (c == PAGE_DOWN && E.cy != E.screenrows-1) E.cy = E.screenrows-1;
        int times = E.screenrows;
        while(times--) editorMoveCursor(c == PAGE_UP ? ARROW_UP : ARROW_DOWN);
        } break;
    case ARROW_UP: case ARROW_DOWN: case ARROW_LEFT: case ARROW_RIGHT:
        editorMoveCursor(c); break;
    case CTRL_L: break;
    case ESC: break;
    default: editorInsertChar(c); break;
    }
    quit_times = KILO_QUIT_TIMES;
}

/* BEFORE (verbatim, kilo.c): reads the global E directly */
int editorFileWasModified(void) {
    return E.dirty;
}

/* AFTER (illustrative rewrite for this book, not in antirez's source):
   state passed explicitly instead of read from a global */
int editorFileWasModified(const struct editorConfig *ed) {
    return ed->dirty;
}

/* Illustrative sketch for this book, not in antirez's source: replacing
   editorProcessKeypress's switch with a data-driven dispatch table. */
typedef void (*KeyHandler)(struct editorConfig *ed, int key);

static const struct { int key; KeyHandler fn; } KEYMAP[] = {
    { ENTER,   handle_enter   },
    { CTRL_Q,  handle_quit    },
    { CTRL_S,  handle_save    },
    { CTRL_F,  handle_find    },
    /* ... */
    { 0, NULL } /* sentinel */
};

void editorProcessKeypress(struct editorConfig *ed, int fd) {
    int c = editorReadKey(fd);
    for (int i = 0; KEYMAP[i].fn; i++)
        if (KEYMAP[i].key == c) { KEYMAP[i].fn(ed, c); return; }
    handle_insert(ed, c); /* default case */
}
